INSERT INTO public.questions (id, subject_id, type, difficulty, content, options, correct_answer, explanation) VALUES ('f783d170-e131-4d94-981b-0001120c2668', 1, 'multiple_choice', 'easy', 'Premis 1: Semua hewan karnivora pemakan daging. Premis 2: Singa adalah hewan karnivora. Kesimpulan yang paling tepat adalah...', '["Singa pemakan daging","Singa bukan hewan","Sebagian singa pemakan daging","Singa pemakan segalanya","Tidak dapat ditarik kesimpulan"]'::jsonb, 'Singa pemakan daging'::jsonb, 'Silogisme sederhana: A -> B, dan x = A, maka x = B.') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, subject_id, type, difficulty, content, options, correct_answer, explanation) VALUES ('2fe7ea58-154f-48e5-adbc-598271328166', 2, 'multiple_choice', 'medium', 'Jika x + y = 10 dan x - y = 4, maka nilai dari x * y adalah...', '["21","24","16","25","20"]'::jsonb, '21'::jsonb, 'x+y=10, x-y=4. Maka 2x=14 -> x=7. y=3. 7*3=21.') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, subject_id, type, difficulty, content, options, correct_answer, explanation) VALUES ('ccf27709-d45c-40af-b6e4-b2c76844173d', 3, 'multiple_choice', 'medium', 'Kata bercetak miring pada kalimat "Dia menatap dengan *tajam*" memiliki makna yang bersinonim dengan...', '["Sinus","Cerdas","Fokus dan keras","Runcing","Luka"]'::jsonb, 'Fokus dan keras'::jsonb, 'Mata yang tajam dalam teks merujuk pada tatapan yang sangat fokus/menusuk secara kiasan.') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, subject_id, type, difficulty, content, options, correct_answer, explanation) VALUES ('7fb844c1-e8de-4ec3-8e7f-835170a63b08', 4, 'multiple_choice', 'hard', 'Negara di kawasan Asia Tenggara yang tidak pernah dijajah oleh bangsa Eropa adalah...', '["Indonesia","Malaysia","Filipina","Thailand","Vietnam"]'::jsonb, 'Thailand'::jsonb, 'Thailand dikenal sebagai negara buffer dan secara historis tidak pernah dijajah secara penuh oleh kolonial Eropa.') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, subject_id, type, difficulty, content, options, correct_answer, explanation) VALUES ('10d74e4a-9d9f-4824-a5a3-cde182159cb0', 7, 'multiple_choice', 'hard', 'Sebuah dadu dilempar dua kali. Peluang munculnya angka berjumlah 7 adalah...', '["1/6","1/12","1/36","5/36","7/36"]'::jsonb, '1/6'::jsonb, 'Kombinasi 7: (1,6), (2,5), (3,4), (4,3), (5,2), (6,1). Total 6/36 = 1/6.') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, subject_id, type, difficulty, content, options, correct_answer, explanation) VALUES ('e7fe6cb3-53d1-47b5-87f4-6a24f557085b', 6, 'multiple_choice', 'medium', 'What is the synonym of the word "astounding"?', '["Boring","Amazing","Terrible","Normal","Fast"]'::jsonb, 'Amazing'::jsonb, '"Astounding" means very surprising or amazing.') ON CONFLICT (id) DO NOTHING;
